(1, 'ABDOL HAMID', 'uploads/cv/0YstU2dCwigezXJU5RTCsOfsMnFCmk2UWjep0L9F.pdf', 'Đại học', 'hamidabdol2002@gmail.com', '0981192884', 'Đại học Quốc gia', 'Công nghệ thông tin', 'Website công ty', 'Chưa có', 1, 1, '2025-01-18 02:18:47', '2025-01-18 02:28:38'),
(2, 'Nguyễn Thanh Minh', 'uploads/cv/PFrvJF465vtgTIkcMGm0sugguljJuZY17qZaeFvb.pdf', 'Thạc sĩ', 'thanhminh@gmail.com', '0986452369', 'Đại học Giang Nam - Trung Quốc', 'Công nghệ kỹ thuật Điện, Điện tử', 'Vietnamwork', 'Kinh nghiệm:\r\nChuyên viên Marketing tại Công ty ABC (2020 - 2023)\r\nTrách nhiệm:\r\nLên kế hoạch và thực hiện các chiến dịch marketing trên các kênh online (Facebook, Google,...)\r\nPhân tích dữ liệu và tối ưu hóa hiệu quả của các chiến dịch\r\nXây dựng và quản lý cộng đồng mạng xã hội\r\nThành tựu:\r\nTăng lượng truy cập website lên 30% trong vòng 6 tháng\r\nGiảm chi phí quảng cáo 15% so với cùng kỳ năm trước\r\nTăng tỷ lệ chuyển đổi khách hàng tiềm năng thành khách hàng thực tế lên 20%\r\nKỹ năng:\r\nThành thạo các công cụ marketing online (Google Analytics, Facebook Ads,...)\r\nKỹ năng viết content SEO, quảng cáo\r\nKỹ năng phân tích dữ liệu, báo cáo\r\nMục tiêu:\r\nTrở thành Trưởng nhóm Marketing, xây dựng và phát triển đội ngũ marketing hiệu quả', 1, 1, '2025-01-18 03:29:59', '2025-04-14 07:21:04'),
(12, 'wefewf', 'uploads/cv/ZnqYAoIThvjE8jmTqQn4NdLutMuglhnz29OGU0Zw.pdf', 'Tiểu học', 'wefwe@gmail.com', '213213', 'Đại học An Giang', 'An toàn thông tin', 'MobiFone.vn', 'wefwe', 0, 0, '2025-01-18 08:32:11', '2025-01-18 08:32:11'),
(13, 'ewfewfsadads', 'uploads/cv/ZJiPurWQN1xFhdgiccPWHkiUcURpfVNSRzbWlBby.pdf', 'Tiểu học', 'qwq@gmail.com', '21321', 'Đại học An Giang', 'An toàn thông tin', 'MobiFone.vn', 'wefewf', 0, 0, '2025-01-18 08:32:59', '2025-01-18 08:32:59'),
