INSERT INTO `dichvus` (`id`, `ten_dich_vu`, `anh`, `noi_dung`, `loai_dich_vu`, `created_at`, `updated_at`) VALUES
(1, 'mobiEdu', 'uploads/k77afzl6yn1IWAh2KLBZ9CufdSfsDhMX7ckD5BJC.png', 'mobiEdu là hệ sinh thái giáo dục trực tuyến toàn diện, cung cấp các khóa học, các ứng dụng và chương trình học tập phong phú dành cho mọi lứa tuổi; các giải pháp trường học số và cổng thi cho các kỳ thi tại Việt Nam.', 'Dịch vụ nổi bật', '2025-03-23 08:26:00', '2025-03-23 08:26:00'),
(2, 'mobiAgri', 'uploads/h4BpWfIaR0BCKhaNqqbvimQQzQqkJwxAPHsNekvH.jpg', 'mobiAgri là nền tảng cung cấp giải pháp trong lĩnh vực nông nghiệp theo hướng chuyển đổi số, nông nghiệp công nghệ cao, ứng dụng các công nghệ Big data, AI, Blockchain, AR, VR,…', 'Dịch vụ nổi bật', '2025-04-01 15:19:20', '2025-04-01 15:19:20'),
(3, 'Thanh Toán Trên Google Play', 'uploads/QyMRO8NqYYfFpMhgeke3C9vrEzw0HxuJMtpQW4TL.jpg', 'Dịch vụ Thanh toán qua tài khoản di động trên Google Play là dịch vụ giúp khách hàng sử dụng thiết bị di động cài đặt hệ điều hành Android thực hiện thanh toán các ứng dụng/nội dung tính phí trên kho ứng dụng Google Play bằng tài khoản di động của mình.', 'Khác', '2025-04-01 15:20:40', '2025-04-01 15:20:40'),
(4, 'Mobi HyperSMS', 'uploads/sHGBBzsUgb97LerlGtpvn5Acqdge9Mz8OrN5XQam.png', 'Mobi HyperSMS  Giải pháp gửi SMS đa phương tiện (hình ảnh, video <30s, âm thanh, text) dung lượng đến **2MB**, tiết kiệm, hiệu quả cho doanh nghiệp. Chỉ cần **1 SMS** thông thường. (250 ký tự)', 'Khác', '2025-04-01 15:28:07', '2025-04-01 15:28:31'),
(5, 'iCall', 'uploads/vFBopL4ROgNlfO8F23jMhGXTgMyVFEAnAERsxg2n.jpg', 'Icall là tổng đài tự động cung cấp gói cước ichat và ifriend nhằm đáp ứng nhu cầu kết nối bạn bè dành cho các TB MobiFone qua kênh IVR với các ưu đãi hấp dẫn .', 'Khác', '2025-04-01 15:32:59', '2025-04-01 15:32:59'),
(6, 'CVQT trên Máy bay và Tàu biển', 'uploads/gYCWR9s2PWCScAUB92rAjjT59erXal8W53cly8u7.jpg', 'MobiFone cung cấp dịch vụ CVQT trên một số chuyến bay và tàu biển của các hãng hàng không và tàu biển có cung cấp dịch vụ này', 'Khác', '2025-04-01 15:37:11', '2025-04-01 15:37:11'),
(7, 'Thông báo cuộc gọi nhỡ (MCA)', 'uploads/DIt7BXpbvKtQUw7ijuDvFZgT0mWiDX4IXwA6PhxJ.jpg', 'Dịch vụ Thông báo cuộc gọi nhỡ (MCA) giúp bạn biết thông tin về các cuộc gọi nhỡ tới số thuê bao của mình khi điện thoại di động của bạn đang tắt máy, hết pin hoặc ngoài vùng phủ sóng.', 'Khác', '2025-04-01 15:47:45', '2025-04-01 15:47:45'),
(8, 'Free Call', 'uploads/JlGdReQnyZjUykOgb2aWZ6t1CEubf2oQMorlZ7pO.png', 'Freecall tích hợp thoại (FCT) là gói cước được ưu đãi 15 phút gọi nội mạng miễn phí mỗi ngày và cho phép khách hàng xem video chất lượng cao tại địa chỉ http://freecall.vn (miễn phí data 3G/4G khi truy cập http://freecall.vn).', 'Khác', '2025-04-01 15:57:07', '2025-04-01 15:57:07'),
(9, 'Witalk', 'uploads/rJnEo3uTwlWEs6Z9pUbl2LxyO99cyfrM5TchhpVm.jpg', 'Witalk là dịch vụ giúp khách hàng gọi điện và gửi tin nhắn thông qua internet với giá cước tiết kiệm.', 'Khác', '2025-04-01 16:00:54', '2025-04-01 16:00:54'),
(10, 'Buzz me', 'uploads/4OglduVwPqV0YG1jT104GS5UhYu5gG81FJRundYe.jpg', 'Buzzme là tính năng cho phép các thuê bao trả trước của MobiFone có thể để lại cuộc gọi nhỡ tới các thuê bao di động khác trong trường hợp tài khoản thuê bao đó hết tiền hoặc không đủ để thực hiện cuộc gọi.', 'Khác', '2025-04-01 16:05:03', '2025-04-01 16:05:03'),
(11, 'Dịch Vụ Thoại Quốc Tế', 'uploads/6U94WuHaT5ZAyLP0VNRTZzcJ72oy2k5faRBaK0jM.jpg', 'Gọi quốc tế là dịch vụ giúp các thuê bao MobiFone gọi tới một số điện thoại nước ngoài từ máy điện thoại di động của mình.', 'Khác', '2025-04-01 16:07:27', '2025-04-01 16:07:27'),
(12, 'Dịch Vụ SMS Quốc Tế', 'uploads/hcEwiE72r5GYkmNnP4aWSFB4AXsJmODItOnmMoiY.jpg', 'Là dịch vụ giúp các thuê bao MobiFone nhắn tin tới một số điện thoại nước ngoài từ máy điện thoại di động của mình.', 'Khác', '2025-04-01 16:08:57', '2025-04-01 16:08:57'),
(13, 'Dịch Vụ Đặt Phòng Khách Sạn', 'uploads/ZFn8Ie9XYofrE57MlEJWf0QtlyWlJNtgid7fL8Pt.jpg', 'Website https://www.hotel.mobifone.vn là một sản phẩm hợp tác giữa MobiFone và Booking.com, cung cấp cho khách hàng dịch vụ đặt phòng/khách sạn lý tưởng trong những chuyến du lịch và công tác của mình một cách dễ dàng và nhanh chóng.', 'Khác', '2025-04-01 16:09:57', '2025-04-01 16:09:57'),
(15, 'wefwe', 'uploads/Da5G6JczCDsstwllBQR4HDeDSkiSCTBlqEzPm7GX.png', 'wef', 'Giáo Dục', '2025-04-13 04:56:43', '2025-04-13 04:56:43');
INSERT INTO `dichvu_chitiet` (`id`, `dichvu_id`, `doi_tuong_su_dung`, `tinh_nang_chinh`, `quy_dinh`, `tien_ich`, `created_at`, `updated_at`) VALUES
(1, 1, 'Người học cá nhân mọi lứa tuổi: mầm non, phổ thông, sinh viên, người đi làm;\r\nNgười dạy là giáo viên, giảng viên, cơ sở đào tạo;\r\nCác tổ chức như Trường học, Doanh nghiệp, Cơ quan nhà nước.', 'mobiEdu cung cấp hàng ngàn khóa học và các chương trình, ứng dụng học tập hàng đầu tới người học qua website https://mobiedu.vn/.\r\n\r\nNội dung học tập phong phú dành cho nhiều đối tượng:\r\n\r\nTrẻ em: các chương trình học tập tiền tiểu học, tiếng Anh, kỹ năng sống, kỹ năng đọc sách, chơi cờ vua, chế tạo robot, STEAM,… Nổi bật là các chương trình: Dino đi học, DoYoSe, VkidsApp, Kynaforkids, mSkill Kid,…\r\nHọc sinh phổ thông: các chương trình ôn luyện, luyện thi, học tâp thuộc bậc giáo dục phổ thông, tiếng Anh, kỹ năng sống… Nổi bật là các sản phẩm: Mobistudy, Smart Edupia, HiClass, ElsaPro, MathX, mSkill, mLearn,…\r\nSinh viên, người đi làm: các chương trình ngoại ngữ (tiếng Anh, Trung, Hàn, Nhật), tin học văn phòng, các kỹ năng mềm, dậy nấu ăn, yoga, rèn luyện sức khỏe,… Nổi bật là các sản phẩm: mWiki, mSkill, Elsa Pro, mEnglish,…\r\nĐặc biệt mobiEdu cung cấp các khóa học theo hình thức “combo”, trả phí qua tài khoản viễn thông với mức cước chỉ từ 2.000đ/ ngày cho các chương trình học tập giá trị cao, kèm theo các ưu đãi về dịch vụ viễn thông (data, thoại) cho khách hàng.\r\n\r\nWebsite : https://mobiedu.vn/\r\n\r\nLiên hệ: 0777.20.20.20', '- Người học cần có thiết bị kết nối internet như điện thoại, máy tính bảng, PC, laptop…\r\n\r\n- Một số chương trình, khóa học có thể đăng ký bằng hình thức chuyển khoản ngân hàng\r\n\r\nWebsite : https://mobiedu.vn/', NULL, '2025-03-23 08:26:38', '2025-03-23 08:26:38'),
(2, 2, 'TB trả trước và trả sau của MobiFone đang hoạt động 2 chiều.', 'Dịch vụ được cung cấp qua  Ứng dụng mobiAgri (Android, IOS) với các tính năng:\r\n\r\nKiểm tra sức khỏe cây trồng – AI: Sử dụng trí tuệ nhân tạo hỗ trợ công tác chẩn đoán và cách điều trị sâu bệnh hại;\r\nCSDL cây trồng và Sâu - Bệnh trên cây trồng: Thư viện canh tác cây trồng giúp tra cứu kỹ thuật chăm sóc nhanh chính xác;\r\nKết nối Hỏi - Đáp cùng Chuyên gia: Nhận tư vấn trực tiếp từ các chuyên gia khi gặp phải vấn đề trong sản xuất;\r\nThông tin khuyến cáo nông vụ & Dự báo thời tiết chuyên sâu: Cảnh báo thời tiết nông vụ nhằm đưa ra kế hoạch sản xuất chính xác.', 'Gói cước sẽ được tự động gia hạn khi hết chu kỳ. Trường hợp trừ cước không thành công, hệ thống sẽ thực hiện trừ cước lại trong 45 ngày tiếp theo, mỗi ngày trừ cước 01 lần. Trường hợp trừ cước không thành công trong 45 ngày liên tiếp, hệ thống sẽ hủy dịch vụ cung cấp cho khách hàng.\r\nWebsite: https://mobiagri.vn/\r\n\r\nỨng dụng (Android, IOS): mobiAgri.\r\n\r\nLiên hệ: 18001090.', NULL, '2025-04-01 15:19:50', '2025-04-01 15:19:50'),
(3, 3, 'Tất cả thuê bao hoạt động 2 chiều trên mạng MobiFone.\r\nThuê bao sử dụng thiết bị hỗ trợ truy cập ứng dụng Google Play và đã đăng ký tài khoản trên Google Play.', 'Giá cước dịch vụ\r\n\r\nGói cước thuê bao dịch vụ: Không áp dụng.\r\n\r\nCước Data: Theo quy định hiện hành.\r\n\r\nCước mua nội dung/ứng dụng (chưa bao gồm thuế GTGT): Theo báo giá trên kho ứng dụng.\r\n\r\nCước nhắn tin SMS (nếu có): Miễn phí.\r\n\r\nLưu ý:\r\n\r\nGiá mua nội dung/ứng dụng trên Google Play chưa bao gồm 10% thuế GTGT.\r\n\r\nKhi thanh toán bằng tài khoản di động, MobiFone sẽ trừ thêm 10% thuế GTGT vào tài khoản chính của khách hàng.\r\n\r\nHạn mức giao dịch (áp dụng từ 20/03/2025):\r\n\r\nThuê bao trả trước:\r\n\r\nTối đa 5.000.000 VND/giao dịch.\r\n\r\nTối đa 7.000.000 VND/tháng.\r\n\r\nThuê bao trả sau:\r\n\r\nTối đa 500.000 VND/giao dịch.\r\n\r\nTối đa 500.000 VND/tháng.\r\n\r\nGhi chú (*)\r\n\r\nĐối với các ứng dụng/nội dung có mức giá vượt quá hạn mức tiêu dùng một giao dịch hoặc hạn mức tiêu dùng tháng, khách hàng chỉ có thể chọn phương thức thanh toán khác.\r\n​​- Hướng dẫn:\r\n\r\nCài đặt dịch vụ\r\nB1. Truy cập CH Play trên điện thoại qua 3G MobiFone – chọn mục “Tài khoản”\r\nB2. Chọn “Thanh toán và gói thuê bao”\r\nB3. Chọn “Phương thức thanh toán”\r\nB4. Chọn “Sử dụng thanh toán qua MobiFone”\r\nB5. Sau khi hoàn tất sẽ thấy tùy chọn “Tính phí vào tài khoản MobiFone của tôi\"\r\nLưu ý:\r\n\r\n•  Khi khách hàng thay Sim khác vào điện thoại đã đăng ký, hệ thống sẽ gửi tin nhắn xác thực thuê bao, giao dịch sẽ được thực hiện trên Sim mới.\r\n\r\nSử dụng dịch vụ\r\nB1. Lựa chọn Ứng dụng/Nội dung muốn thanh toán\r\nB2. Nhập mật khẩu Google Play\r\nB3. Click Mua\r\nB4. Hoàn tất mua ứng dụng\r\n \r\n\r\nLưu ý:\r\nLựa chọn Xem chi tiết tại cuối trang để tra cứu Mã số bưu chính Việt Nam\r\nHóa đơn mua hàng sẽ được gửi về email đăng ký trên Google Play của khách hàng\r\nViệc mua ứng dụng được xác thực bằng mật khẩu Google Play của khách hàng\r\nKhách hàng có thể lựa chọn nhớ mật khẩu trong các lần thanh toán sau. Tuy nhiên khuyến nghị khách hàng chọn hỏi mật khẩu trong tất cả mọi lần mua ứng dụng, để tránh phát sinh cước ngoài ý muốn.\r\nViệc mua sắm trong ứng dụng (in-app purchase) được thực hiện hoàn toàn tương tự như mua ứng dụng/nội dung trên Google Play.', '- Các trường hợp không thanh toán được\r\n\r\nThuê bao không đáp ứng được yêu cầu để sử dụng cổng thanh toán của MobiFone\r\nTài khoản chính của thuê bao không đủ tiền.\r\n- Nguyên tắc trừ cước:\r\n\r\nVới thuê bao trả trước: Cước dịch vụ sẽ được trừ vào tài khoản chính.\r\nĐối với thuê bao trả sau: Cước dịch vụ sẽ được tính vào hóa đơn cước hàng tháng.\r\n- Quy định khác:\r\n\r\nMobiFone có quyền từ chối yêu cầu thanh toán của Khách hàng để bảo vệ quyền lợi của Khách hàng hoặc đáp ứng việc tuân thủ các qui định pháp luật Việt Nam hiện hành.', NULL, '2025-04-01 15:23:50', '2025-04-01 15:23:50'),
(4, 4, 'Tất cả các khách hàng doanh nghiệp có nhu cầu sử dụng dịch vụ HyperSMS để truyền thông tới khách hàng, doanh nghiệp, tổ chức một cách hiệu quả, chuyên nghiệp.\r\nThủ tục đăng ký:\r\nHồ sơ pháp lý đầy đủ, có nội dung quảng cáo phù hợp theo quy định của phát luật và quy định của MobiFone.\r\nMọi sản phẩm quảng cáo phải được MobiFone kiểm tra và phê duyệt trước khi triển khai quảng cáo tới khách hàng.\r\nHotline: 0762 072 660\r\nTruy cập website: https://mbf.hypersms.vn', 'Giá cước dịch vụ (đã bao gồm thuế GTGT)\r\n\r\n1. Giá cước dịch vụ quảng cáo:\r\n- Khách hàng nhận tin nhắn hoàn toàn miễn phí data\r\n- Chỉ tính phí khi bản tin được download thành công\r\n- Tin nhắn quảng cáo: 700 đồng/bản tin\r\n- Tin nhắn chăm sóc khách hàng: 1.100 đồng/bản tin\r\n\r\n2. Chính sách chiết khấu cho đại lý:\r\n\r\nĐối với tin nhắn quảng cáo:\r\n- Dưới 500.000 tin: 700đ/tin, không chiết khấu (3 tháng)\r\n- 500.001-1.000.000 tin: 665đ/tin (chiết khấu 5%, 3 tháng)\r\n- 1.000.001-3.000.000 tin: 651đ/tin (7%, 3 tháng)\r\n- 3.000.001-5.000.000 tin: 630đ/tin (10%, 3 tháng)\r\n- 5.000.001-10.000.000 tin: 595đ/tin (15%, 3 tháng)\r\n- 10.000.001-20.000.000 tin: 560đ/tin (20%, 3 tháng)\r\n- 20.000.001-40.000.000 tin: 525đ/tin (25%, 6 tháng)\r\n- Trên 40.000.000 tin: 490đ/tin (30%, 6 tháng)\r\n\r\nĐối với tin nhắn chăm sóc khách hàng:\r\n- Dưới 500.000 tin: 1.100đ/tin, không chiết khấu (3 tháng)\r\n- 500.001-2.000.000 tin: 1.045đ/tin (5%, 3 tháng)\r\n- 2.000.001-3.000.000 tin: 1.023đ/tin (7%, 3 tháng)\r\n- 3.000.001-4.000.000 tin: 990đ/tin (10%, 6 tháng)\r\n- 4.000.001-5.000.000 tin: 957đ/tin (13%, 6 tháng)\r\n- Trên 5.000.000 tin: 935đ/tin (15%, 6 tháng)\r\n\r\nTất cả mức giá đã bao gồm thuế GTGT 10%', 'Hotline: 0762 072 660\r\nTruy cập website: https://mbf.hypersms.vn', NULL, '2025-04-01 15:31:55', '2025-04-01 15:31:55'),
(5, 5, 'Tất cả các thuê bao trả trước, trả sau đang hoạt động hai chiều trên mạng MobiFone', 'Tính năng chính của dịch vụ:\r\n\r\nKhi đăng ký gói cước, khách hàng sẽ được tặng phút gọi miễn phí nội mạng MobiFone thông qua tổng đài 1522. Có thể đăng ký qua các kênh: SMS, IVR hoặc Wapsite. Kênh sử dụng chính là IVR.\r\n\r\nCách đăng ký và hủy dịch vụ:\r\n\r\nĐăng ký qua tin nhắn SMS:\r\n- Gói iChat ngày (IC): soạn DK IC gửi đến 1522\r\n  + Ưu đãi: 30 phút gọi miễn phí mỗi ngày qua tổng đài 1522\r\n  + Lưu ý: Miễn phí ngày đầu tiên đăng ký, dịch vụ tự động gia hạn\r\n- Gói iChat tuần (IC7): soạn DK IC7 gửi 1522\r\n  + Ưu đãi: 100 phút gọi miễn phí mỗi tuần\r\n- Gói iFriend ngày (IF): soạn DK IF gửi 1522\r\n  + Ưu đãi: 50 phút gọi miễn phí mỗi ngày\r\n- Gói iFriend tuần (IF7): soạn DK IF7 gửi 1522\r\n  + Ưu đãi: 150 phút gọi miễn phí mỗi tuần\r\n\r\nHủy dịch vụ:\r\nSoạn tin nhắn HUY [tên gói] gửi đến 1522. Ví dụ: HUY IC gửi 1522 để hủy gói iChat ngày.\r\n\r\nHướng dẫn sử dụng:\r\n1. Gọi đến số 1522, nhấn phím 5 và làm theo hướng dẫn để nhập số thuê bao MobiFone cần gọi\r\n2. Cách gọi nhanh: quay số 1522 + số MobiFone cần gọi liền nhau (ví dụ: 1522090123456)\r\n\r\nLưu ý: Để được tính vào phút gọi miễn phí, tất cả cuộc gọi phải được thực hiện qua tổng đài 1522 theo đúng gói đã đăng ký.', 'Quy định sử dụng dịch vụ:\r\n\r\n1. Tính năng kết nối:\r\n- Hệ thống sẽ ngừng cung cấp tính năng kết nối nội mạng qua tổng đài 1522 khi khách hàng sử dụng hết số phút miễn phí của gói cước.\r\n- Khách hàng sẽ nhận được tin nhắn thông báo khi sử dụng hết quyền lợi gọi miễn phí.\r\n\r\n2. Hiệu lực gói cước:\r\n- Gói ngày: Có hiệu lực ngay sau khi đăng ký/gia hạn thành công, kéo dài đến 23h59\'59\" của ngày hôm sau.\r\n- Gói tuần: Có hiệu lực ngay sau khi đăng ký/gia hạn thành công, kéo dài đến 23h59\'59\" của ngày thứ 7 sau ngày đăng ký.\r\n\r\n3. Phương thức thanh toán:\r\n- Thuê bao trả sau: Thanh toán qua hóa đơn hàng tháng.\r\n- Thuê bao trả trước: Trừ trực tiếp vào tài khoản chính.\r\n- Gói cước tự động gia hạn nếu khách hàng không hủy.\r\n\r\n4. Thời gian trừ cước:\r\n- Hệ thống trừ cước từ 0h đến 4h hàng ngày.\r\n- Nếu hủy dịch vụ khi chưa hết hiệu lực gói, khách hàng phải thanh toán đầy đủ cước phí nếu đăng ký lại.\r\n\r\n5. Cơ chế trừ cước bậc thang:\r\n- Tài khoản ≥ 3.000đ: trừ 3.000đ\r\n- Tài khoản từ 2.000đ đến dưới 3.000đ: trừ 2.000đ\r\n- Tài khoản từ 1.000đ đến dưới 2.000đ: trừ 1.000đ\r\n\r\n6. Quy định đăng ký lại:\r\n- Nếu hủy và đăng ký lại trong cùng ngày: vẫn bị trừ cước đầy đủ.\r\n- Nếu hủy và đăng ký lại từ ngày thứ 2: áp dụng cơ chế trừ cước mới.\r\n\r\n7. Xử lý khi không trừ được cước:\r\n- Nếu không trừ được cước liên tục trong 45 ngày: hệ thống tự động hủy gói.\r\n- Khách hàng cần đăng ký lại nếu muốn tiếp tục sử dụng dịch vụ.', NULL, '2025-04-01 15:36:24', '2025-04-01 15:36:24'),
(6, 6, 'Tất cả các thuê bao của MobiFone', 'Cho phép khách hàng giữ liên lạc trong thời gian di chuyển bằng máy bay/tàu biển;\r\nKhông gây ảnh hưởng đến an toàn chuyến bay.', 'Giá cước (đã bao gồm VAT):\r\n\r\n1. Dịch vụ thoại:\r\n- Cước thực hiện cuộc gọi: 69.990 VND/phút\r\n- Cước nhận cuộc gọi: 69.990 VND/phút\r\n\r\n2. Dịch vụ SMS:\r\n- Cước gửi SMS: 15.990 VND/bản tin\r\n- Cước nhận SMS: Miễn phí\r\n\r\n3. Dịch vụ data (chỉ áp dụng cho CVQT trên tàu biển):\r\n- 4.990 VND/10kB\r\n\r\nNguyên tắc tính cước:\r\n- Dịch vụ thoại: Tính theo block 1 phút + 1 phút. Số giây lẻ được làm tròn lên 1 phút.\r\n- Dịch vụ SMS: Tính theo bản tin (160 ký tự không dấu hoặc 70 ký tự có dấu).\r\n- Dịch vụ data: Tính theo block 10kB + 10kB.\r\n\r\nHướng dẫn sử dụng:\r\n- Dịch vụ CVQT trên máy bay được cung cấp bởi mạng On Air và AeroMobile.\r\n- Dịch vụ CVQT trên tàu biển được cung cấp bởi mạng MCP (Telenor Maritime).\r\n\r\nLưu ý quan trọng:\r\n1. Trên máy bay:\r\n- Khách hàng phải tắt điện thoại trong quá trình cất cánh và hạ cánh.\r\n- Chỉ được sử dụng dịch vụ khi máy bay đạt độ cao ổn định (từ 3.000m trở lên) và được phi hành đoàn thông báo.\r\n- Kết nối qua mạng On Air hoặc AeroMobile.\r\n\r\n2. Trên tàu biển:\r\n- Chỉ sử dụng được khi tàu đang ở vùng biển quốc tế.\r\n\r\nLiên hệ hỗ trợ:\r\nĐể biết thêm chi tiết, vui lòng gọi tổng đài 18001090 để được tư vấn.', NULL, '2025-04-01 15:42:29', '2025-04-01 15:45:57'),
(7, 7, 'Thuê bao MobiFone đang hoạt động 2 chiều.', 'Dịch vụ thông báo cuộc gọi nhỡ cung cấp các tính năng sau:\r\n\r\n• Nhận và tra cứu thông tin các cuộc gọi nhỡ\r\n• Tích hợp với danh bạ để hiển thị tên người gọi (theo tên đã lưu trong danh bạ)\r\n• Thiết lập thời gian ngừng nhận thông báo cuộc gọi nhỡ\r\n• Nhận thông báo cuộc gọi nhỡ qua email\r\n• Chuyển tiếp thông báo đến số thuê bao MobiFone khác\r\n• Sử dụng dễ dàng trên website: mca.mobifone.vn\r\n\r\nCách hủy gói dịch vụ:\r\n\r\n• Gói ngày (500đ/ngày): Soạn HUY gửi 9232\r\n• Gói tuần (2.500đ/7 ngày): Soạn HUY gửi 9232\r\n• Gói tháng (9.000đ/30 ngày): Soạn HUY gửi 9232\r\n\r\n(Lưu ý: Tất cả gói đều hủy bằng cú pháp HUY gửi 9232, hệ thống sẽ tự động nhận diện gói đang sử dụng)', 'Gói cước sẽ được tự động gia hạn khi hết chu kỳ sử dụng. Trường hợp trừ cước không thành công, hệ thống sẽ tiếp tục thử trừ cước trong 30 ngày tiếp theo.\r\n\r\nĐể nhận được bản tin thông báo cuộc gọi nhỡ, thuê bao cần đảm bảo các điều kiện sau: đang hoạt động hai chiều, không trong tình trạng tắt máy, hết pin hoặc nằm ngoài vùng phủ sóng quá 24 giờ tính từ thời điểm có cuộc gọi đến.\r\n\r\nKhách hàng có thể truy cập website mca.mobifone.vn để biết thêm thông tin chi tiết. Mọi thắc mắc vui lòng liên hệ tổng đài 18001090 (phí gọi 200 đồng/phút).', NULL, '2025-04-01 15:51:35', '2025-04-01 15:55:45'),
(8, 8, 'TB MobiFone trả trước, trả sau đang hoạt động 02 chiều.', 'Gói Freecall: cung cấp 15 phút gọi nội mạng mỗi ngày, xem video chất lượng cao (miễn cước data) tại http://freecall.vn.', 'Dịch vụ Freecall cung cấp:\r\n\r\n• Giá cước: 3.000đ/ngày\r\n• Cách đăng ký: Soạn DK FCT hoặc FCT gửi 9199\r\n• Ưu đãi bao gồm:\r\n  • 15 phút gọi nội mạng mỗi ngày\r\n  • Xem video chất lượng cao không giới hạn dung lượng tại freecall.vn\r\n• Hủy dịch vụ: Soạn HUY FCT gửi 9199\r\n\r\n(Lưu ý: Dịch vụ sẽ tự động gia hạn hàng ngày nếu không hủy)', NULL, '2025-04-01 15:58:44', '2025-04-01 15:59:52'),
(9, 9, 'Tất cả các thuê bao đang hoạt động hai chiều trên mạng MobiFone.', 'Dịch vụ kết nối internet Witalk\r\n\r\n• Giúp liên lạc qua internet với chi phí tiết kiệm\r\n• Khắc phục tình trạng sóng di động yếu tại nhiều khu vực\r\n\r\nCách đăng ký:\r\n• Điện thoại Android: Cần cài đặt ứng dụng Witalk\r\n• Điện thoại iOS: Chỉ cần bật tính năng Wi-Fi Calling có sẵn (không cần cài ứng dụng)\r\n\r\nBảng giá cước:\r\n\r\nA. Cước thoại:\r\n- Thuê bao ở nước ngoài:\r\n  + Gọi về Việt Nam: 2.500đ/phút\r\n  + Gọi quốc tế: 2.500đ/phút\r\n- Thuê bao tại Việt Nam:\r\n  + Gọi đến thuê bao MobiFone: 690đ/phút\r\n  + Gọi liên mạng trong nước: 690đ/phút\r\n  + Gọi quốc tế: 2.500đ/phút\r\n\r\nB. Cước SMS (không phân biệt vị trí):\r\n- Gửi SMS trong nước: 300đ/tin nhắn\r\n- Gửi SMS quốc tế: 1.000đ/tin nhắn\r\n\r\n(Lưu ý: Áp dụng giới hạn đối với một số quốc gia)', 'Để sử dụng dịch vụ WiTalk:\r\n\r\nThuê bao sử dụng SIM 4G của MobiFone.\r\nĐối với điện thoại Apple iPhone, sử dụng từ iPhone 6 - phiên bản iOS từ 8.0 trở lên.', NULL, '2025-04-01 16:02:19', '2025-04-01 16:03:33'),
(10, 10, '• Thuê bao thực hiện cuộc gọi – Thuê bao A: thuê bao MobiFone trả trước đang hoạt động 02 chiều.\r\n• Thuê bao nhận cuộc gọi – Thuê bao B: Thuê bao di động nội mạng, ngoại mạng MobiFone (Viettel, Vinaphone, Vietnamobile, Gmobile).', 'Dịch vụ Buzz Me giúp duy trì liên lạc giữa các thuê bao:\r\n• Khi thuê bao A gọi không thành công do hết tiền, hệ thống sẽ tạo cuộc gọi nhỡ cho thuê bao B\r\n• Thuê bao B sẽ biết có cuộc gọi từ thuê bao A và có thể gọi lại\r\n\r\nCách đăng ký và sử dụng (soạn tin nhắn gửi 9283):\r\n1. Đăng ký: DK\r\n2. Hủy dịch vụ: HUY\r\n3. Tắt Buzz Me với 1 số: HUY SốĐT\r\n4. Bật lại Buzz Me với 1 số: BAT SốĐT\r\n5. Kiểm tra danh sách từ chối: DS\r\n6. Kiểm tra trạng thái: KT\r\n7. Từ chối nhận Buzz Me: TC\r\n8. Đồng ý nhận Buzz Me: DY\r\n9. Từ chối nhận từ 1 số cụ thể: TC SốĐT\r\n10. Đồng ý nhận từ 1 số cụ thể: DY SốĐT\r\n11. Xem hướng dẫn: HD\r\n\r\nLưu ý: Dịch vụ được cung cấp miễn phí cho tất cả thuê bao trả trước MobiFone.', NULL, NULL, '2025-04-01 16:06:31', '2025-04-01 16:06:31'),
(11, 11, 'Dịch vụ Gọi quốc tế được mở tự động cho tất cả các thuê bao trả trước và trả sau trên mạng MobiFone', 'Dịch vụ Gọi quốc tế được mở tự động cho tất cả các thuê bao trả trước và trả sau trên mạng MobiFone\r\n\r\nNếu muốn huỷ hoặc đăng ký lại dịch vụ. Quý khách vui lòng thực hiện qua tin nhắn SMS như sau:\r\n\r\nSoạn QT gửi 9199 để đăng ký lại dịch vụ\r\n\r\nSoạn CHAN_QT gửi 9199 để huỷ dịch vụ', 'Thuê bao đăng ký và sử dụng dịch vụ trong phạm vi lãnh thổ Việt Nam có phủ sóng của MobiFone\r\n\r\nMức cước áp dụng cho các thuê bao trả trước, trả sau trên mạng MobiFone.\r\n\r\nMức cước không phụ thuộc vào mức độ sử dụng dịch vụ trong tháng.\r\n\r\nMức cước không phân biệt giờ cao điểm, giờ thấp điểm.', 'Gọi trực tiếp IDD: Từ máy điện thoại, khách hàng quay số:\r\n\r\nMã thoát + Mã nước + Mã vùng/Mã mạng + Số điện thoại cần gọi\r\n\r\n(Trong đó: Mã thoát là 00 hoặc dấu+)\r\n\r\nGọi VoIP 131: Từ máy điện thoại, khách hàng quay số:\r\n\r\n131 + 00 + mã nước + mã vùng/mã mạng + Số điện thoại cần gọi', '2025-04-01 16:08:16', '2025-04-01 16:08:16'),
(12, 12, 'Đối tượng sử dụng: Dịch vụ SMS quốc tế được mở tự động cho tất cả các thuê bao trả trước và trả sau trên mạng MobiFone.\r\n\r\nĐiều kiện sử dụng: Thuê bao đăng ký và sử dụng dịch vụ trong phạm vi lãnh thổ Việt Nam có phủ sóng của MobiFone.', 'Khách hàng soạn nội dung tin nhắn, gửi tới số điện thoại nước ngoài theo cú pháp:\r\n\r\nMã thoát + Mã nước + Mã vùng/Mã mạng + Số điện thoại cần gọi\r\n\r\n(Trong đó: Mã thoát là 00 hoặc dấu +)', 'Nhắn tin từ điện thoại di động: 2.500 VNĐ/ SMS.\r\n\r\nNhắn tin từ cổng thông tin của MobiFone: 1.900 VNĐ/SMS.\r\n\r\nĐơn vị tính giá: 1 SMS tối đa bao gồm chuỗi 160 ký tự không dấu hoặc 70 ký tự có dấu.', NULL, '2025-04-01 16:09:20', '2025-04-01 16:09:20'),
(13, 13, 'Toàn bộ thuê bao MobiFone truy cập website https://www.hotel.mobifone.vn', 'Miễn phí data (3G/4G) cho thuê bao MobiFone khi truy cập website đồng thương hiệu (www.hotel.mobifone.vn).\r\n\r\nTặng 1GB Data cho thuê bao MobiFone khi đặt phòng, sử dụng phòng, trả phòng và thanh toán thành công dịch vụ phòng/khách sạn trên website đồng thương hiệu (áp dụng cho các đơn đặt phòng có giá trị từ 450.000đ trở lên).\r\n\r\nƯu đãi giá phòng lên đến 60% (áp dụng đối với các phòng khách sạn/căn hộ… có gắn logo ưu đãi của MobiFone).', 'Toàn bộ các chính sách, quy định, thủ tục đặt phòng khách sạn trên website https://www.hotel.mobifone.vn được tuân thủ theo đúng chính sách, quy định của Booking.com.\r\n\r\nChính sách miễn phí data (3G/4G) cho thuê bao MobiFone khi truy cập website chỉ áp dụng cho thuê bao MobiFone sử dụng data trên lãnh thổ Việt Nam, không áp dụng cho thuê bao MobiFone chuyển vùng quốc tế tại nước ngoài.\r\n\r\nTừ 0h00’ ngày 1/11/2018 đến 24h00’ ngày 31/12/2018, thuê bao MobiFone sẽ được nhận 1GB DATA cho mỗi đặt phòng có giá trị từ 450.000đ trở lên (bao gồm các bước đặt phòng, nhận phòng, sử dụng, trả phòng và thanh toán thành công theo đúng quy định của Booking.com) qua website đồng thương hiệu  https://www.hotel.mobifone.vn:\r\n\r\nThời hạn sử dụng: 10 ngày, kể từ thời điểm hệ thống cộng dung lượng data ưu đãi vào tài khoản của khách hàng;\r\n\r\nThời điểm cộng dung lượng data ưu đãi: Ngày vàng khuyến mại của tháng n+2 (Trong đó, tháng n là tháng mà khách hàng trả phòng thành công).\r\n\r\nVí dụ:\r\n\r\nKhách hàng đặt phòng từ ngày 30/10 - 05/11/2018 (trả phòng ngày 05/11/2018),\r\n\r\n=> Ngày 07/01/2019, hệ thống sẽ cộng 1GB data ưu đãi (thời hạn sử dụng: 10 ngày) vào số thuê bao MobiFone mà khách hàng đã đăng ký trên website .\r\n\r\nHoặc, Khách hàng đặt phòng từ ngày 05/12 - 15/12/2018 (trả phòng ngày 15/12/2018),\r\n\r\n=> Ngày 08/02/2019, hệ thống sẽ cộng 1GB data ưu đãi (thời hạn sử dụng: 10 ngày) vào số thuê bao MobiFone mà khách hàng đã đăng ký trên website .\r\n\r\nTrong trường hợp khách hàng thực hiện nhiều đặt phòng trong 01 tháng, dung lượng data ưu đãi sẽ được cộng dồn tương ứng và thời hạn sử dụng cho tổng dung lượng data ưu đãi tối đa là 30 ngày, kể từ thời điểm hệ thống cộng dung lượng data ưu đãi vào tài khoản của khách hàng.\r\n\r\nVí dụ:\r\n\r\nKhách hàng thực hiện 02 đặt phòng thành công, bao gồm đặt phòng 1: từ ngày 30/10 - 05/11 (trả phòng vào ngày 05/11); đặt phòng 2: từ ngày 10/11 – 15/11 (trả phòng vào ngày 15/11).\r\n\r\n=> Ngày 07/01/2019, hệ thống sẽ cộng 2GB data ưu đãi (thời hạn sử dụng: 20 ngày) vào số thuê bao MobiFone mà khách hàng đã đăng ký trên website  https://www.hotel.mobifone.vn.\r\n\r\nKhách hàng thực hiện 05 đặt phòng thành công, bao gồm đặt phòng 1: từ ngày 30/10 - 05/12 (trả phòng vào ngày 05/12); đặt phòng 2: từ ngày 07/12 (trả phòng vào ngày 07/12); đặt phòng 3: từ ngày 10/12 - 12/12 (trả phòng vào ngày 12/12); đặt phòng 4: từ ngày 31/12 (trả phòng vào ngày 31/12).\r\n\r\n=> Ngày 08/02/2019, hệ thống sẽ cộng 4GB data ưu đãi (thời hạn sử dụng: 30 ngày) vào số thuê bao MobiFone mà khách hàng đã đăng ký trên website https://www.hotel.mobifone.vn.', NULL, '2025-04-01 16:10:32', '2025-04-01 16:10:32');
