(113, 52, 'Giới thiệu dịch vụ', 'Dịch vụ Chuyển vùng quốc tế (Roaming) của MobiFone giúp các thuê bao giữ liên lạc khi ra nước ngoài bằng chính số điện thoại đang sử dụng của mình.', '2025-04-01 11:56:04', '2025-04-01 11:56:04'),
(114, 52, 'Khi đăng ký dịch vụ CVQT Thoại&SMS, bạn có thể', 'Gọi và nhận cuộc gọi', '2025-04-01 11:56:04', '2025-04-01 11:56:04'),
(115, 52, 'Bạn không thể', 'Truy cập data CVQT.', '2025-04-01 11:56:04', '2025-04-01 11:56:04'),
(116, 52, 'Lưu ý khi đăng ký dịch vụ CVQT Thoại & SMS', 'Bạn nên đăng ký dịch vụ CVQT tại Việt Nam để đảm bảo sử dụng được dịch vụ.', '2025-04-01 11:56:04', '2025-04-01 11:56:04'),
(117, 52, 'TBTS hoạt động dưới 90 ngày', 'Không thể đăng ký dịch vụ này. Thuê bao cần liên hệ với các cửa hàng MobiFone để được hỗ trợ.', '2025-04-01 11:56:04', '2025-04-01 11:56:04'),
(118, 52, 'Truy cập data CVQT', 'Nếu bạn muốn truy cập data CVQT, bạn cần đăng ký dịch vụ CVQT ALL (Thoại, SMS & Data) để sử dụng dịch vụ data với giá cước CVQT thông thường.', '2025-04-01 11:56:04', '2025-04-01 11:56:04'),
(119, 52, 'Cách đăng ký CVQT ALL', 'Soạn DK CVQT ALL gửi 9199 hoặc bấm *093*2*1#OK', '2025-04-01 11:56:04', '2025-04-01 11:56:04'),
(120, 52, 'Gói cước ưu đãi', 'Bạn có thể đăng ký các gói cước CVQT ưu đãi để yên tâm sử dụng dịch vụ CVQT mà không lo phát sinh thêm cước phí.', '2025-04-01 11:56:04', '2025-04-01 11:56:04'),
