INSERT INTO `loaithuebao` (`id`, `subscription_type_id`, `benefits`, `pricing`, `instructions`, `created_at`, `updated_at`) VALUES
(1, 1, 'Cước SMS thấp: 200 đồng/SMS nội mạng, 250 đồng/SMS liên mạng.\r\n\r\nKhông giới hạn thời gian sử dụng: tự động gia hạn 60 ngày mỗi khi phát sinh giao dịch nạp tiền hoặc cuộc gọi, tin nhắn,… có tính cước.', 'Giá bán bộ hòa mạng: 50.000 đồng/bộ (đã bao gồm VAT), trong đó:\r\n\r\nGiá bán SIM: 25.000 đồng\r\nCước hòa mạng: 25.000 đồng\r\nCước thoại và SMS:\r\n\r\nCước thoại:\r\nNội mạng: 1.580 đồng/phút\r\nLiên mạng: 1.780 đồng/phút.\r\nCước SMS:\r\nNội mạng: 200 đồng/SMS.\r\nLiên mạng: 250 đồng/SMS.\r\nCước SMS quốc tế:\r\nTừ điện thoại di động: 2.500 đồng/SMS.\r\nTừ webportal: 1.900 đồng/SMS.\r\nCước khác:\r\nCước quốc tế IDD: Chỉ bao gồm cước IDD\r\nGọi dịch vụ 1080/1088/hộp thư thông tin: Cước dịch vụ 108x.\r\nĐơn vị tính cước: 6 giây + 1', 'Đăng ký gói cước: tại cửa hàng, đại lý, các điểm phân phối chính thức của MobiFone trên toàn quốc.\r\n\r\nThủ tục hoà mạng:\r\n\r\nBạn cần có 01 bản sao và 01 bản gốc giấy tờ tùy thân (bao gồm CMTND, CM quân đội, CM công an, hoặc  hộ chiếu còn thời hạn).\r\n\r\nĐối với  khách hàng có địa chỉ thường trú trên CMT khác với nơi khách hàng hòa mạng (về mặt địa lý), cần các giấy tờ sau:\r\n\r\n01 bản sao và 01 bản gốc Chứng minh thư (hoặc CM nhân dân, CM quân đội, CM công an, hộ chiếu còn thời hạn)\r\n\r\nBản photo hộ khẩu, hoặc giấy đăng ký tạm trú thời hạn trên 6 tháng.\r\n\r\nTrong trường hợp khách hàng không có các giấy tờ trên, các giấy tờ đăng ký thay thế là:Hộ chiếu còn thời hạn (ít nhất 03 tháng trở lên) hoặc Giấy xác nhận của cơ quan đơn vị (bản gốc) đối với trường hợp đang công tác trên địa bàn do Trung tâm quản lý.\r\n\r\n \r\n\r\nThời hạn sử dụng\r\n\r\nKhông giới hạn thời gian sử dụng: tự động gia hạn 60 ngày mỗi khi phát sinh giao dịch nạp tiền hoặc cuộc gọi, tin nhắn,… có tính cước.\r\nNếu trong vòng 60 ngày, thuê bao không thực hiện một trong các giao dịch phát sinh cước, nạp tiền.... thì sẽ bị khóa 1 chiều (chỉ nhận được cuộc gọi đến và tin nhắn SMS đến). Thời gian khóa 1 chiều: 10 ngày.\r\nSau 10 ngày, số thuê bao tiếp tục bị khóa 2 chiều trong 30 ngày tiếp theo.\r\nĐể mở lại dịch vụ trong thời gian khóa 1 chiều, khóa 2 chiều, khách hàng chỉ cần nạp tiền vào Tài khoản SIM.\r\nSau 30 ngày, số thuê bao bị cắt hủy và thu hồi về kho số của MobiFone để cấp cho khách hàng khác có nhu cầu.\r\n\r\nLoại thuê bao khác\r\nMobiCard\r\nMobiCard\r\nMobiCard là gói cước trả trước được thiết kế phù hợp với người không có nhu cầu nhắn tin nhiều và gọi khoảng từ 30 tới 135 phút/tháng. Ngoài chất lượng cuộc gọi hoàn hảo, bạn sẽ hoàn toàn', '2025-01-21 03:34:45', '2025-01-21 14:06:37'),
(3, 2, 'Dễ dàng kiểm soát chi phí: Không cước thuê bao, không hóa đơn cước.\r\nNạp thẻ đơn giản, đa dạng: \r\n•    Mua thẻ cào tại các điểm bán sim/thẻ của MobiFone (cửa hàng, đại lý, điểm bán)\r\n•    Hệ thống thanh toán trực tuyến\r\n•    Trang nạp tiền của MobiFone\r\n•    Tài khoản Fastpay', 'Giá bộ hòa mạng: 50.000 đồng/ bộ hòa mạng (đã bao gồm VAT), trong đó:\r\n\r\nGiá bán SIM: 25.000 đồng\r\n\r\nCước hòa mạng: 25.000 đồng.\r\n\r\nCước thoại và SMS:\r\n\r\nCước thoại:\r\nNội mạng: 1.180 đồng/phút\r\nLiên mạng: 1.380 đồng/phút\r\nCước SMS:\r\nNội mạng: 290 đồng/SMS\r\nLiên mạng: 350 đồng/SMS\r\nCước SMS quốc tế:\r\nTừ điện thoại di động: 2.500 đồng/SMS\r\nTừ webportal: 1.900 đồng/SMS.\r\nCước khác:\r\nCước quốc tế IDD: Chỉ bao gồm cước IDD\r\nGọi dịch vụ 1080/1088/hộp thư thông tin: Cước dịch vụ 108x.', 'Đăng ký sử dụng: mua bộ trọn gói ban đầu MobiCard tại cửa hàng, đại lý, các điểm phân phối chính thức của MobiFone trên toàn quốc. \r\n\r\n \r\n\r\nThời hạn sử dụng:\r\n\r\nThời hạn sử dụng của thuê bao theo mệnh giá thẻ nạp tiền mà khách hàng nạp vào tài khoản.\r\nKhi hết thời hạn sử dụng, thuê bao sẽ bị khóa 1 chiều và chỉ có thể nhận cuộc gọi và nhận tin nhắn trong thời gian 10 ngày.\r\nSau 10 ngày, số thuê bao tiếp tục bị khóa 2 chiều trong 30 ngày tiếp theo.\r\nĐể mở lại dịch vụ trong thời gian khóa 1 chiều, khóa 2 chiều, khách hàng chỉ cần nạp tiền vào Tài khoản SIM.\r\nSau 30 ngày, số thuê bao bị cắt hủy và thu hồi về kho số của MobiFone để cấp cho khách hàng khác có nhu cầu', '2025-01-21 14:04:58', '2025-01-21 14:04:58'),
(4, 3, 'Cước gọi rẻ: 880 đồng/phút nội mạng, 980 đồng/phút liên mạng.\r\n\r\nThanh toán cước đơn giản, đa dạng\r\n\r\nTại nhà\r\nQua hệ thống ATM\r\nTại các điểm thu cước của MobiFone\r\nHệ thống thanh toán trực tuyến\r\nTài khoản Fastpay\r\nNhiều ưu đãi\r\n\r\nChương trình chúc mừng sinh nhật, tặng quà cho khách hàng đặc biệt\r\nChương trình kết nối dài lâu (chương trình điểm thưởng của MobiFone): bạn sẽ được hưởng các dịch vụ chăm sóc đặc biệt tại các khu nghỉ dưỡng, khách sạn hàng đầu của Việt Nam, tại các bệnh viện quốc tế,…', 'Giá bán bộ hòa mạng: 60.000 đồng/bộ (đã bao gồm VAT), trong đó:\r\n\r\nGiá bán SIM: 25.000 đồng\r\n\r\nCước hòa mạng: 35.000 đồng\r\n\r\nCước thuê bao: 49.000 đồng/chu kỳ/thuê bao (đã bao gồm VAT)\r\n\r\nCước thoại và SMS:\r\n\r\nCước thoại:\r\nNội mạng: 880 đồng/phút\r\nLiên mạng: 980 đồng/phút\r\nCước SMS:\r\nNội mạng: 290 đồng/SMS\r\nLiên mạng: 350 đồng/SMS\r\nCước SMS quốc tế:\r\nTừ điện thoại di động: 2.500 đồng/SMS\r\nTừ webportal: 1.900 đồng/SMS.\r\nCước khác:\r\nCước quốc tế IDD: Chỉ bao gồm cước IDD\r\nGọi dịch vụ 1080/1088/hộp thư thông tin: Cước dịch vụ 108x.\r\nĐơn vị tính cước: 6 giây +1', 'Đăng ký gói cước: tại cửa hàng, đại lý, các điểm phân phối chính thức của MobiFone trên toàn quốc.\r\n\r\nThủ tục hoà mạng\r\n\r\nBạn cần có 01 bản sao và 01 bản gốc giấy tờ tùy thân (bao gồm CMTND hoặc hộ chiếu còn thời hạn).\r\nNếu bạn có địa chỉ thường trú trên CMT khác với nơi bạn hòa mạng (về mặt địa lý), cần các giấy tờ sau:\r\n01 bản sao và 01 bản gốc CMT (hoặc CM nhân dân, hộ chiếu còn thời hạn);\r\nBản photo hộ khẩu, hoặc giấy đăng ký tạm trú thời hạn trên 6 tháng;\r\nTrong trường hợp bạn không có các giấy tờ trên, các giấy tờ đăng ký thay thế là: Hộ chiếu còn thời hạn (ít nhất 03 tháng trở lên) hoặc Giấy xác nhận của cơ quan đơn vị (bản gốc) đối với trường hợp đang công tác trên địa bàn do Trung tâm quản lý.', '2025-01-21 14:09:08', '2025-01-21 14:09:08'),
(5, 6, 'KHÔNG cước thuê bao tháng.\r\nMIỄN PHÍ THOẠI tất cả các cuộc gọi nội mạng dưới 10 phút, DATA khủng.\r\nCHỦ ĐỘNG KIỂM SOÁT CƯỚC bằng hạn mức đăng ký trước.', 'Giá cước thuê bao tháng: 0 đồng\r\n\r\nGói cước mua kèm: Các thuê bao MobiF phải mua kèm 1 trong các gói cước sau đây trong suốt thời gian sử dụng dịch vụ:\r\n\r\n1. MF69:\r\n\r\nThoại nội mạng: 1.000 phút nội mạng.\r\nThời hạn sử dụng: 01 tháng.\r\nGiá gói (Đã bao gồm thuế GTGT): 69.000 VNĐ.\r\n2. MF99:\r\n\r\nThoại nội mạng: Miễn phí cuộc gọi nội mạng dưới 10 phút (Tối đa 1.000 phút).\r\nThoại trong nước: 40 phút.\r\nData: 5GB.\r\nThời hạn sử dụng: 01 tháng.\r\nGiá gói (Đã bao gồm thuế GTGT): 99.000 VNĐ.​\r\n3. MF149:\r\n\r\nThoại nội mạng: Miễn phí cuộc gọi nội mạng dưới 10 phút (Tối đa 1.500 phút).\r\nThoại trong nước: 80 phút.\r\nData: 8GB.\r\nThời hạn sử dụng: 01 tháng.\r\nGiá gói (Đã bao gồm thuế GTGT): 149.000 VNĐ.​\r\n4. MF199:\r\n\r\nThoại nội mạng: Miễn phí cuộc gọi nội mạng dưới 10 phút (Tối đa 1.500 phút).\r\nThoại trong nước: 160 phút.\r\nData: 9GB.\r\nThời hạn sử dụng: 01 tháng.\r\nGiá gói (Đã bao gồm thuế GTGT): 199.000 VNĐ.​\r\n5. MF299:\r\n\r\nThoại nội mạng: Miễn phí cuộc gọi nội mạng dưới 10 phút (Tối đa 2.000 phút).\r\nThoại trong nước: 300 phút.\r\nData: 12GB.\r\nThời hạn sử dụng: 01 tháng.\r\nGiá gói (Đã bao gồm thuế GTGT): 299.000 VNĐ.​\r\n6. MF399:\r\n\r\nThoại nội mạng: Miễn phí cuộc gọi nội mạng dưới 10 phút (Tối đa 3.000 phút).\r\nThoại trong nước: 400 phút.\r\nData: 17GB.\r\nThời hạn sử dụng: 01 tháng.\r\nGiá gói (Đã bao gồm thuế GTGT): 399.000 VNĐ.​\r\n6. MF499:\r\n\r\nThoại nội mạng: Miễn phí cuộc gọi nội mạng dưới 10 phút (Tối đa 4.000 phút).\r\nThoại trong nước: 500 phút.\r\nData: 22GB.\r\nThời hạn sử dụng: 01 tháng.\r\nGiá gói (Đã bao gồm thuế GTGT): 499.000 VNĐ.​\r\n7. MF599:\r\n\r\nThoại nội mạng: Miễn phí cuộc gọi nội mạng dưới 10 phút (Tối đa 5.000 phút).\r\nThoại trong nước: 600 phút.\r\nData: 25GB.\r\nThời hạn sử dụng: 01 tháng.\r\nGiá gói (Đã bao gồm thuế GTGT): 599.000 VNĐ.​\r\n7. MF799:\r\n\r\nThoại nội mạng: Miễn phí cuộc gọi nội mạng dưới 10 phút (Tối đa 7.000 phút).\r\nThoại trong nước: 700 phút.\r\nData: 35GB.\r\nThời hạn sử dụng: 01 tháng.\r\nGiá gói (Đã bao gồm thuế GTGT): 799.000 VNĐ.​\r\n8. MF999:\r\n\r\nThoại nội mạng: Miễn phí cuộc gọi nội mạng dưới 10 phút (Tối đa 10.000 phút).\r\nThoại trong nước: 1.000 phút.\r\nData: 45GB.\r\nThời hạn sử dụng: 01 tháng.\r\nGiá gói (Đã bao gồm thuế GTGT): 999.000 VNĐ.​\r\n \r\n\r\n10. MF200:\r\n\r\nThoại nội mạng: 1.000 phút\r\nThoại trong nước: 300 phút.\r\nData: 4GB/ngày.\r\nThời hạn sử dụng: 1 chu kỳ.\r\nGiá gói (Đã bao gồm thuế GTGT): 200.000 VNĐ.​\r\n11. MF250:\r\n\r\nThoại nội mạng: 1.000 phút\r\nThoại trong nước: 400 phút.\r\nData: 4GB/ngày.\r\nThời hạn sử dụng: 1 chu kỳ.\r\nGiá gói (Đã bao gồm thuế GTGT): 250.000 VNĐ.​\r\n12. MF300:\r\n\r\nThoại nội mạng: 1.000 phút\r\nThoại trong nước: 500 phút.\r\nData: 4GB/ngày.\r\nThời hạn sử dụng: 1 chu kỳ.\r\nGiá gói (Đã bao gồm thuế GTGT): 300.000 VNĐ.\r\nGiá cước ngoài gói:\r\n\r\nCước gọi nội mạng trong nước: 880 đồng/phút (đã bao gồm VAT).\r\nCước gọi liên mạng trong nước: 980 đồng/phút (đã bao gồm VAT).\r\nCước nhắn tin nội mạng trong nước: 290 đồng/SMS (đã bao gồm VAT).\r\nCước nhắn tin liên mạng trong nước: 350 đồng/SMS (đã bao gồm VAT).\r\nPhương thức tính cước:\r\n\r\n- Theo block 6s+1;\r\n\r\n- Tính cước ngay từ giây đầu tiên;\r\n\r\n- Cuộc gọi dưới 6 giây được tính là 6 giây;\r\n\r\n- Tính cước block 01 giây kể từ giây thứ 7.', 'Chọn hạn mức để kiểm soát chi tiêu\r\n\r\nTB hòa mạng gói cước MobiF phải đăng ký hạn mức cho phần cước trả sau (đã bao gồm giá gói cước cam kết mua kèm) theo các mức quy định sau:\r\n\r\nHạn mức cước trả sau:\r\n\r\nMức 1: 100.000 VNĐ.\r\nMức 2: 200.000 VNĐ.\r\nMức 3: 300.000 VNĐ.\r\nMức 4: 500.000 VNĐ.\r\nMức 5: 1.000.000 VNĐ.\r\nMức 6: 2.000.000 VNĐ.\r\n​Nếu không đăng ký: Hạn mức mặc định là 200.000đ\r\n\r\n\r\nKhách hàng soạn tin nhắn: HMC_số tiền gửi 999Thay đổi hạn mức cước trả sau\r\n\r\nTrong đó: Số tiền là hạn mức cước trả sau khách hàng muốn thay đổi. Hạn mức thực hiện theo quy định trong bảng trên. Số tiền nhập đầy đủ không có khoảng cách, không có kí tự xen giữa. Sau khi nhắn tin thành công, hạn mức mới sẽ có hiệu lực từ chu kì tiếp theo liền sau\r\nKiểm tra hạn mức gói cước \r\n\r\nKhách hàng nhắn tin kiểm tra Dung lượng còn lại của các gói cước: KT_ALL gửi 999\r\nTra cứu hạn mức bằng USSD: *112#', '2025-01-21 14:10:16', '2025-01-21 14:10:16'),
(6, 7, 'Kết nối Internet tốc độ cao mọi lúc, mọi nơi\r\n\r\nCài đặt, sử dụng dịch vụ đơn giản, dễ dàng\r\n\r\nSử dụng dịch vụ với giá cước linh hoạt và kiểm soát được cước phí sử dụng dịch vụ', 'Tên gói\r\n\r\nGiá gói (đã bao gồm VAT)\r\n\r\nDung lượng miễn phí tốc độ tối đa\r\n\r\nCước ngoài gói (50kB+50kB)\r\n\r\nGói 30 ngày\r\n\r\nFCO\r\n\r\n0\r\n\r\n0\r\n\r\n \r\n\r\nF70\r\n\r\n70.000đ/30 ngày\r\n\r\n7GB\r\n\r\n \r\n\r\n9,77đ/50kB (tương đương 200đ/MB)\r\n\r\nF90N*\r\n\r\n90.000đ/30 ngày\r\n\r\n9GB\r\n\r\nF120\r\n\r\n120.000đ/30 ngày\r\n\r\n12GB\r\n\r\nF200\r\n\r\n200.000đ/30 ngày\r\n\r\n20GB\r\n\r\nF300\r\n\r\n300.000đ/30 ngày\r\n\r\n30GB\r\n\r\nData50\r\n\r\n50.000đ/30 ngày\r\n\r\n3,5 GB\r\n\r\n(Trong đó 2,5 GB sử dụng trong vùng đăng ký (*), 1 GB sử dụng trong nước)\r\n\r\nGói thời hạn dài\r\n\r\nF150\r\n\r\n150.000đ/90 ngày\r\n\r\n3GB/30 ngày\r\n\r\nKhông áp dụng\r\n\r\nF250\r\n\r\n250.000đ/180 ngày\r\n\r\n3GB/30 ngày\r\n\r\nF500N\r\n\r\n500.000đ/360 ngày\r\n\r\n \r\n\r\n4GB/30 ngày\r\n\r\n(*) F90N: Khi sử dụng hết dung lượng miễn phí, không thể truy cập Internet', 'Đăng ký thuê bao\r\n\r\nĐể đăng ký thuê bao Fast Connect, bạn có thể thực hiện theo một trong các cách sau:\r\n\r\nHòa mạng mới SIM Fast Connect trả trước, Fast Connect trả sau tại của hàng của MobiFone trên toàn quốc.\r\nChuyển đổi từ các loại hình thuê bao khác sang thuê bao Fast Connect:\r\nChuyển đổi từ thuê bao trả trước thông thường sang Fast Connect trả trước: Soạn PFC gửi 900 hoặc bấm *090*5*10*1#OK hoặc *111*6#OK và làm theo hướng dẫn.\r\nCác hình thức chuyển đổi khác: Tại cửa hàng MobiFone.\r\nPhí chuyển đổi: Miễn phí.\r\nCách sử dụng thiết bị\r\n\r\nĐể sử dụng thiết bị và SIMCard Fast Connect bạn có thể thực hiện theo một trong các cách sau:\r\n\r\nSử dụng DataCard (đã được lắp SIMCard đăng ký dịch vụ Fast Connect) cắm vào cổng USB để truy nhập Internet từ máy tính xách tay hoặc máy tính để bàn.\r\nSử dụng máy tính xách tay có sẵn khe cắm SIMCard để thực hiện kết nối Internet thông qua mạng di động.\r\nSử dụng máy tính xách tay truy cập internet thông qua giao thức WI-FI, tiếp nhận sóng từ thiết bị phát sóng Wi-Fi có sử dụng SIMCard MobiFone.\r\nĐăng ký/Hủy/Gia hạn gói cước\r\n\r\nBạn có thể Đăng ký, Hủy, Gia hạn, Tặng và Kiểm tra tình trạng gói cước qua các kênh SMS, USSD, website MobiFone:\r\n\r\nQua SMS:\r\nYêu cầu\r\n\r\nCú pháp nhắn tin đến 999\r\n\r\nĐăng ký dịch vụ\r\n\r\nDATA ON\r\n\r\nĐăng ký gói cước\r\n\r\nDK TênGóiCước\r\n\r\nHủy gói cước\r\n\r\nHUY TênGóiCước\r\n\r\nGia hạn gói cước\r\n\r\nGH TênGóiCước\r\n\r\nKhông gia hạn gói cước\r\n\r\nKGH\r\n\r\nTặng gói cước\r\n\r\nTANG TênGóiCước ThuêBaoNhận \r\n\r\nKiểm tra gói cước\r\n\r\nKT DATA\r\n\r\nTrợ giúp\r\n\r\nTG FC \r\n\r\nQua USSD: bạn bấm *090*5*10#OK và làm theo hướng dẫn.\r\nQua website: bạn đăng nhập www.mobifone.vn bằng tài khoản MobiFone Portal và làm theo hướng dẫn.\r\nLưu ý: Sau khi đăng ký dịch vụ, đăng ký, gia hạn gói cước Fast Connect, bạn cần tắt tất cả ứng dụng Internet và khởi động lại thiết bị để được tính cước theo gói cước đã đăng ký.', '2025-01-21 14:11:20', '2025-01-21 14:11:20'),
