INSERT INTO `news` (`id`, `title`, `content`, `category`, `image`, `published_at`, `created_at`, `updated_at`, `kiemduyet`, `kichhoat`) VALUES
(1, 'HÒA MẠNG THUÊ BAO, NHẬN NGAY VOUCHER', '<p><i>Từ 06/01 đến hết 31/03/2025, khách hàng khi mua SIM kèm gói cước thông qua ứng dụng My MobiFone sẽ được tặng miễn phí voucher mua sắm/ ăn uống trên dịch vụ MyPoint.</i></p><p>Năm 2025, MobiFone tiếp tục tri ân khách hàng với nhiều chương trình ưu đãi hấp dẫn. Mở đầu năm mới, MobiFone dành tặng miễn phí lên tới hàng chục nghìn voucher mua sắm, ăn uống trên My Point cho khách hàng mới mua SIM và đăng kí gói cước.</p><p>Cụ thể, từ 06/01 - 31/03/2025, khách hàng khi hòa mạng thành công (kèm đăng kí gói cước) trên ứng dụng My MobiFone sẽ được tặng thêm voucher mua sắm, ăn uống có giá trị từ 15.000đ cho đến 1 triệu đồng từ các thương hiệu trên thị trường như KFC, Sói Biển, Be food, Le Monde, Pizza Company, Shang Chi, Canifa, Điện máy chợ lớn…</p><figure class=\"image image_resized\" style=\"width:818.4px;\"><img src=\"https://api.mobifone.vn/images/notifications/1735782290594_1.2.25.jpg\" alt=\"\"></figure><p>Để nhận ưu đãi từ chương trình, thuê bao thực hiện theo các bước sau:</p><ul><li>Bước 1: Truy cập website simso.mobifone.vn hoặc website <a href=\"https://chonso.mobifone.vn/\">chonso.mobifone.vn</a>, hoặc&nbsp; ứng dụng My MobiFone &gt;&gt; Tính năng “Mua SIM”</li><li>Bước 2: Chọn số, gói cước</li><li>Bước 3: Lựa chọn hình thức SIM (SIM vật lý/eSIM) và thực hiện thanh toán trực tuyến qua 1 trong các hình thức: VNPay QR, Ví MoMo Thẻ ATM nội địa, Thẻ thanh toán Quốc tế…&nbsp; hoặc hình thức thanh toán COD</li><li>Bước 4: Tải ứng dụng My MobiFone, thực hiện đăng ký thông tin, hòa mạng thuê bao&nbsp; trả trước</li><li>Bước 5: Truy cập đường dẫn trong SMS mà hệ thống MyMobiFone đã gửi, làm theo hướng dẫn để chọn mã voucher yêu thích.&nbsp;</li><li>Bước 6: Truy cập ứng dụng My MobiFone hoặc MyPoint, tiến hành đăng nhập và chọn mục “Ưu đãi”&nbsp; để sử dụng voucher.</li></ul><p>Lưu ý:</p><ul><li>Mỗi khách hàng chỉ được nhận ưu đãi 01 lần, tương ứng 01 mã voucher trong thời gian diễn ra chương trình.</li><li>Mã voucher có thời gian hiệu lực nhất định và sẽ được thông báo cụ thể với từng mã voucher, khách hàng cần sử dụng mã voucher trong thời gian hiệu lực.</li><li>Voucher đã chọn không thể đổi trả và không có giá trị quy đổi thành tiền mặt.</li></ul><p>Mọi thông tin chi tiết liên hệ 9090 để được hỗ trợ.</p>', 'tin-khuyen-mai', 'news/qbVapXsMyRBUtjgoCDhdzo0L5Sbf0sSYrraZ0VRo.jpg', '2025-01-13 02:14:27', '2025-01-13 02:14:27', '2025-01-13 03:44:05', 1, 1),
(2, 'MobiFone nâng cao trải nghiệm khách hàng, khẳng định trách nhiệm với xã hội trong năm 2024', '<p><i>Trong năm 2024, MobiFone đã triển khai nhiều giải pháp đột phá nhằm nâng cao trải nghiệm của khách hàng, đồng thời triển khai nhiều chương trình an sinh xã hội có ý nghĩa đối với cộng đồng.</i></p><p>Năm 2024 vừa qua, ngành viễn thông tiếp tục đối mặt với nhiều thách thức. Sự suy giảm về doanh thu, lợi nhuận cũng như sự cạnh tranh trong ngành đã đặt ra cho các doanh nghiệp không ít khó khăn. Điều này bắt buộc các doanh nghiệp phải thay đổi, cải tiến, liên tục chuyển mình thì mới có thể giữ chân khách hàng, nâng cao lợi thế cạnh tranh trên thị trường.</p><p>Trên hành trình đổi mới chuyển mình trở thành doanh nghiệp công nghệ hàng đầu Việt Nam, Tổng công ty Viễn thông MobiFone đã gặt hái nhiều thành công. Năm 2024, nhà mạng hoàn thành xuất sắc các chỉ tiêu được giao, với mức lợi nhuận và nộp ngân sách nhà nước đều vượt kế hoạch. Góp phần không nhỏ tạo nên sự thành công này, phải kể đến cái ‘tâm” của MobiFone đối với khách hàng và xã hội.</p><p><strong>Nâng cấp hạ tầng - Nâng tầm trải nghiệm</strong></p><p>Năm 2024, MobiFone tiếp tục lấy khách hàng làm trung tâm, nỗ lực nâng cao trải nghiệm của người dùng bằng cách nâng cấp mạng lưới, đa dạng hóa dịch vụ nhằm phục vụ tốt nhất cho người dân và doanh nghiệp. Nhà mạng khẳng định vai trò tiên phong trong xây dựng và phát triển hạ tầng số, đồng hành cùng Chính phủ trong việc hiện thực hóa hệ thống hạ tầng viễn thông hiện đại, đồng bộ và bền vững.</p><figure class=\"image image_resized\" style=\"width:818.4px;\"><img src=\"https://api.mobifone.vn/images/notifications/1735275059640_2712.jpg\" alt=\"\"></figure><p>MobiFone đã từng bước triển khai các giải pháp mang tính đột phá, bao gồm: tăng cường đầu tư hạ tầng tại các thành phố lớn và các khu vực khó tiếp cận, mở rộng vùng phủ sóng, hợp tác sử dụng tối đa nguồn lực có sẵn, qua đó đảm bảo chất lượng mạng lưới ổn định và đáp ứng nhu cầu ngày càng cao của khách hàng. Các dự án đầu tư 4G, 5G đã triển khai trong năm 2024 sẽ giúp nâng cao đáng kể năng lực mạng lưới của MobiFone.</p><p>Trong năm 2024, chất lượng mạng lưới của MobiFone được duy trì ổn định tại nhiều sự kiện lớn, tập trung đông người. Bằng việc áp dụng công nghệ số vào vận hành và quản lý mạng lưới, MobiFone đã cải thiện đáng kể khả năng phát hiện và xử lý sự cố, đảm bảo dịch vụ đạt chất lượng tốt nhất, đường truyền thông suốt, từ đó giảm 17% phản ánh của khách hàng.</p><p>Bên cạnh hạ tầng số, các nền tảng hạ tầng cho IoT, hạ tầng dữ liệu, điện toán đám mây cũng được MobiFone đặc biệt quan tâm thúc đẩy. Năm 2024, lần đầu tiên MobiFone đã được cấp chứng chỉ quốc tế \"TIA 942 Rated 3\" cho hệ thống Trung tâm dữ liệu của MobiFone. Dự án Trung tâm Dữ liệu lớn, tập trung của Tổng công ty tại Khu công nghệ cao Hoà Lạc cũng đã được chính thức cấp Giấy phép đầu tư và đang triển khai gấp rút, mở ra khả năng kinh doanh rộng hơn cho Data Center của MobiFone. Cùng với hạ tầng dữ liệu, Tổng công ty cũng đã hoàn thiện hệ sinh thái sản phẩm dịch vụ đi kèm, ra mắt 15 dịch vụ mới như VPC, Load Balancer, Object Storage…</p><p>Những nỗ lực này của MobiFone không chỉ kịp thời đón bắt nhu cầu của thị trường dữ liệu Việt Nam, mà còn là cam kết mạnh mẽ của MobiFone trong việc tham gia xây dựng hạ tầng thiết yếu phục vụ đời sống người dân và hoạt động của doanh nghiệp, đồng thời thực hiện đúng chủ trương của Chính phủ về phát triển hạ tầng số Quốc gia.</p><p><strong>Trách nhiệm của một doanh nghiệp vì cộng đồng</strong></p><p>2024 cũng là năm MobiFone tiếp tục khẳng định trách nhiệm của một doanh nghiệp vì cộng đồng. Trước tình hình thời tiết căng thẳng do siêu bão Yagi – cơn bão mạnh nhất đổ bộ Việt Nam vào tháng 9, lãnh đạo Tổng công ty đã khẩn trương chỉ đạo các đơn vị liên quan, trực tiếp tới các điểm nóng; huy động tối đa nguồn lực, vật lực tại chỗ và trên toàn MobiFone để đảm bảo an toàn mạng lưới, khắc phục nhanh chóng các sự cố do bão, lũ gây ra.</p><figure class=\"image image_resized\" style=\"width:818.4px;\"><img src=\"https://api.mobifone.vn/images/notifications/1735275117324_2712b.jpg\" alt=\"\"></figure><p>Đồng thời, MobiFone và các nhà mạng khác đã phối hợp roaming hỗ trợ khách hàng khi sử dụng dịch vụ, đảm bảo giữ liên lạc ổn định và thông suốt, nhanh chóng khôi phục mạng lưới phục vụ điều hành của chính quyền địa phương và nhu cầu liên lạc của khách hàng tại các vùng chịu ảnh hưởng bởi bão, lũ. Các cửa hàng MobiFone tại khu vực bị ảnh hưởng mở cửa liên tục để phục vụ người dân: hỗ trợ sạc điện, cung cấp nước máy, wifi miễn phí và kích hoạt SIM tại chỗ cho khách hàng.</p><p>Bên cạnh đó, các cán bộ công nhân viên toàn Tổng công ty đã quyên góp số tiền gần 2 tỷ đồng và dành tặng nhiều phần quà hiện vật có giá trị cho bà con vùng bão, lũ, đồng thời tặng hơn 50 tỷ đồng vào tài khoản giúp khách hàng duy trì liên lạc liên tục.</p><p>Cũng trong năm 2024, MobiFone tiếp tục triển khai nhiều chương trình an sinh xã hội ý nghĩa, như ủng hộ nhà đại đoàn kết tại nhiều tỉnh, thành phố; xây dựng các điểm trường tại những khu vực khó khăn; đóng góp trong các chương trình do Mặt trận Tổ quốc Việt Nam và mặt trận Tổ quốc các cấp phát động.</p><p>Thông qua hàng loạt những đóng góp và nỗ lực kể trên, MobiFone đã khẳng định rõ trách nhiệm của một doanh nghiệp vì cộng đồng, cam kết xây dựng một xã hội vững mạnh và nhân văn. Nhà mạng đã thực hiện tốt sứ mệnh đồng hành cùng khách hàng, cho thấy tấm lòng nhân ái, tinh thần đồng cảm, cam kết cống hiến nhằm nâng cao chất lượng đời sống cho người dân Việt Nam.</p>', 'tin-tuc-su-kien', 'news/h4dginHczAoyjzZgbh73kzEkjB0KLZKcFHxL2Pl7.jpg', '2025-01-13 03:29:22', '2025-01-13 03:29:22', '2025-01-13 04:38:11', 1, 1),
(3, 'NGHE NHẠC ĐỈNH CAO, THĂNG HOA CẢM XÚC', '<p><i>Trong bối cảnh nghe nhạc trực tuyến lên ngôi, DV Nền tảng âm nhạc Nhạc Của Tui không ngừng cải tiến, mang đến tính năng cá nhân hóa nhạc theo tâm trạng, gợi ý bài hát theo sở thích và bổ sung cả chế độ hát karaoke. Với giao diện thân thiện, Nhạc Của Tui ngày càng khẳng định vị thế trong lòng người dùng Việt.</i></p><p>Gói cước&nbsp;<strong>12NCT155</strong>&nbsp;kết hợp chất lượng âm thanh đỉnh cao và nhiều ưu đãi viễn thông, là người bạn đồng hành lý tưởng trong cuộc sống.</p><figure class=\"image image_resized\" style=\"width:565.556px;\"><img src=\"https://api.mobifone.vn/images/notifications/1735176780357_nhaccuatui2612.png\" alt=\"\"></figure><p>Để trải nghiệm trọn vẹn các tính năng của DV Nền tảng âm nhạc Nhạc Của Tui mà không dính quảng cáo, người dùng hãy đăng kí ngay gói cước&nbsp;<strong>12NCT155</strong>. Gói cước nghe nhạc dài kỳ này không chỉ mang đến những phút giây thăng hoa cảm xúc mà còn tặng thêm cho người dùng nhiều quyền lợi giải trí, viễn thông thiết thực như:</p><ul><li>1.980GB tốc độ cao trong 12 tháng, tha hồ lướt mạng xã hội không lo thiếu data</li><li>12 tháng miễn phí xem trọn 5 kênh K+ Mobile và hơn 150 kênh truyền hình trong nước và quốc tế trên ứng dụng ClipTV</li><li>Miễn phí 50 phút gọi liên mạng mỗi 30 ngày</li><li>Miễn phí tất cả cuộc gọi nội mạng dưới 10 phút (Tối đa 1.500 phút/30 ngày).</li><li>01 tài khoản VIP NCT nghe nhạc chất lượng cao không lo gián đoạn bởi quảng cáo</li><li>01 tài khoản Night Voiz FM nghe sách và podcast</li></ul><p>Soạn&nbsp;<strong>12NCT155&nbsp;</strong>gửi 999 để bước vào thế giới giải trí bất tận của MobiFone ngay hôm nay.</p><p>Giá gói cước: 1.860.000đ/12 tháng.</p><p>Thông tin chi tiết liên hệ 9090 để được hỗ trợ.</p>', 'tin-khuyen-mai', 'news/Q2uStRxTZSgNssn9nPBSiLISgKbTlY8nlikdMR33.jpg', '2025-01-13 04:50:40', '2025-01-13 04:50:40', '2025-01-13 05:30:30', 1, 1),
(4, 'Thông báo kết quả chào giá cạnh tranh Thuê dịch vụ bảo vệ', '<p>Tên đơn vị: Công ty dịch vụ MobiFone Khu vực 5 – Chi nhánh Tổng công ty Viễn thông MobiFone.</p><p>Địa chỉ: Khu Phú Hải, Phường Anh Dũng, Quận Dương Kinh, Thành phố Hải Phòng, Việt Nam.</p><p>1. Tên gói chào giá: Thuê dịch vụ bảo vệ cho tòa nhà 332 Ngô Gia Tự và các văn phòng MobiFone Quận Huyện.</p><p>Thuộc phương án: Thuê dịch vụ bảo vệ cho tòa nhà 332 Ngô Gia Tự và các văn phòng MobiFone Quận Huyện.</p><p>2. Tên nhà cung cấp được đề nghị trúng chào giá cạnh tranh: Công ty Cổ phần Dịch vụ Bảo vệ Việt Long.</p><p>3. Giá đề nghị trúng chào giá: 1.994.850.000 đồng.</p><p><i>(Bằng chữ: Một tỷ chín trăm chín mươi bốn triệu, tám trăm năm mươi nghìn đồng).</i></p><p>Trong đó: Giá trước thuế: 1.813.500.000 đồng</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Thuế GTGT: &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;199.485.000 đồng</p>', 'tin-tuc-su-kien', 'news/y3HaTGu9az4k63rABgyAt6ui5ug3exECTLHDLRKH.jpg', '2025-01-13 05:06:59', '2025-01-13 05:06:59', '2025-04-14 08:29:58', 1, 1),
(5, 'Lễ ký kết thỏa thuận hợp tác giữa MobIFone và Tổng cục Du lịch', '<p>Ngày 26/06/2015 tại Hà Nội, Tổng cục Du lịch – Bộ Văn hóa, Thể thao và Du lịch và Tổng Công ty Viễn thông MobiFone – Bộ Thông tin và Truyền thông tiến hành ký kết Thỏa thuận Hợp tác&nbsp;nhằm phát huy tiềm năng, thế mạnh của hai bên với mục đích hỗ trợ nhau cùng phát triển, tăng cường thu hút khách du lịch quốc tế đến Việt Nam và thúc đẩy du lịch nội địa, phát triển kinh doanh và chăm sóc khách hàng.<br>Tham dự&nbsp;lễ&nbsp;ký&nbsp;có sự hiện diện của&nbsp;Lãnh đạo Bộ Văn hóa, Thể thao và Du lịch, Lãnh đạo Bộ Thông tin và Truyền thông, Lãnh đạo Tổng Công ty viễn thông MobiFone, Lãnh đạo Tổng cục Du lịch, đại diện một số cơ quan cùng các phóng viên báo chí trên địa bàn Hà Nội.<br>Theo nội dung thỏa thuận hợp tác,&nbsp;hai bên xác định là đối tác của nhau trong việc cung cấp thông tin về du lịch Việt Nam cho khách hàng trong nước và nước ngoài của MobiFone nhằm quảng bá du lịch Việt Nam và chăm sóc khách hàng MobiFone tốt hơn, đồng thời&nbsp;hai bên thống nhất triển khai một số nội dung cụ thể:</p><p>Tổng cục Du lịch cung cấp thông tin về du lịch Việt Nam cho cổng thông tin về du lịch trong nước cho khách hàng sử dụng dịch vụ của Tổng Công ty viễn thông MobiFone để tuyên truyền, quảng bá về đất nước, con người, văn hóa du lịch Việt Nam</p><p>Thường xuyên cập nhật thông tin về du lịch Việt Nam cho khách hàng trong nước và quốc tế sử dụng dịch vụ của Tổng Công ty viễn thông MobiFone thông qua cổng du lịch Halo Vietnam nhằm thu hút khách du lịch quốc tế đến Việt Nam và thúc đẩy du lịch nội địa;</p><p>Triển khai thương mại điện tử trong lĩnh vực du lịch trong tương lai;</p><p>Phối hợp quảng bá truyền thông Cổng thông tin du lịch Halo Vietnam thông qua các hoạt động quảng bá trong phạm vi cho phép của hai bên.</p><p>Thỏa thuận Hợp tác giữa Tổng Công ty viễn thông MobiFone và Tổng cục Du lịch tạo tiền đề để&nbsp;hai bên có thể ưu tiên quảng bá hình ảnh cho nhau trên các kênh truyền thông, các sản phẩm dịch vụ và các sự kiện trong phạm vi được phép của các bên.<br>Tổng cục Du lịch là tổ chức trực thuộc Bộ Văn hóa, Thể thao và Du lịch, thực hiện chức năng tham mưu, giúp Bộ trưởng Bộ Văn hóa, Thể thao và Du lịch quản lý nhà nước và tổ chức thực thi pháp luật về du lịch trong phạm vi cả nước, quản lý các dịch vụ công về du lịch theo quy định của pháp luật. Một trong các nhiệm vụ trọng tâm của Tổng cục Du lịch là tổ chức các hoạt động xúc tiến du lịch quốc gia ở trong nước và ở nước ngoài; điều phối các hoạt động xúc tiến du lịch liên vùng, liên địa phương. Xác định marketing điện tử là một trong những giải pháp quan trọng, hiệu quả để tăng cường công tác tuyên truyền, quảng bá, xúc tiến du lịch; đặc biệt là các chương trình sử dụng mạng thông tin toàn cầu, mạng xã&nbsp;hội và các ứng dụng trên điện thoại thông minh Tổng cục Du lịch sẵn sàng phối hợp với các đối tác để triển khai.<br>Tổng Công ty Viễn thông MobiFone là doanh nghiệp lớn trong lĩnh vực viễn thông và công nghệ thông tin, hoạt động theo mô hình công ty mẹ - công ty con.&nbsp;Được thành lập từ năm 1993, MobiFone đã có bề dày 22 năm hoạt động tại Việt Nam. MobiFone đã vinh dự đón nhận Huân chương Độc lập Hạng 3 do Chủ tịch nước CHXHCN Việt Nam trao tặng năm 2013; Danh hiệu Anh hùng lao động năm 2011 và 6 năm liên tục đạt danh hiệu mạng di động được ưa chuộng nhất, mạng di động chăm sóc khách hàng tốt nhất; Hiện nay Tổng Công ty viễn thông MobiFone đang cung cấp dịch vụ cho hơn 40 triệu thuê bao tại Việt Nam. Năm 2014, MobiFone đã ban hành gói cước Happy Tourist kèm theo hướng dẫn sử dụng bằng 6 ngôn ngữ: Anh, Trung Quốc, Nga, Nhật, Hàn Quốc và tiếng Việt dành riêng cho khách du lịch quốc tế tới Việt Nam. Mới đây nhất, theo văn bản số 4786/VPCP-KTTH ngày 24/06/2015 về việc xếp hạng Tổng công ty đặc biệt, Tổng công ty viễn thông Mobifone đã vinh dự được công nhận là Tổng công ty xếp hạng đặc biệt.<br>Sản phẩm cụ thể mà hai bên phối hợp xây dựng trong phạm vi hợp tác này là cổng thông tin du lịch Halo Vietnam. Đây là cổng dịch vụ cung cấp thông tin và các điểm đến du lịch, ẩm thực, khách sạn, nhà hàng, giải trí,… tại các địa điểm, thành phố ở Việt Nam. Halo Vietnam cho phép khách hàng thực hiện việc đánh giá điểm đến du lịch, tham gia góp ý cho môi trường du lịch Việt Nam để cải thiện chất lượng dịch vụ của hai Bên. Trong tương lai, khách hàng có thể đặt chỗ và đăng ký trực tuyến các dịch vụ du lịch thông qua cổng thông tin du lịch Halo Vietnam.&nbsp;Cổng thông tin du lịch Halo Vietnam&nbsp;được khai trương ngay sau khi hai bên ký hợp tác thỏa thuận này.<br>Sự kiện này thể hiện MobiFone luôn tăng cường kết nối với các đơn vị hữu quan nhằm khơi dậy những tiềm năng trong việc sáng tạo cung cấp những sản phẩm, dịch vụ hữu ích tới khách hàng. Thông qua thỏa thuận hợp tác này, Tổng Công ty viễn thông MobiFone và Tổng cục Du lịch một lần nữa khẳng định cam kết luôn hợp tác, chia sẻ cùng hướng tới mục tiêu chung vì lợi ích của khách hàng và sự phát triển bền vững của hai bên.</p>', 'thong-cao-bao-chi', 'news/EWVZQdMY4wVxomE4QY2y1I8thQBWKK988ESLM0Nf.jpg', '2025-01-13 05:08:17', '2025-01-13 05:08:17', '2025-01-13 05:30:24', 1, 1);
