INSERT INTO `subscription_types` (`id`, `name`, `title`, `subscription_category`, `image`, `is_approved`, `created_at`, `updated_at`) VALUES
(1, 'MobiQ', 'MobiQ là gói cước trả trước được thiết kế phù hợp với người nhắn tin thường xuyên nhưng chỉ có nhu cầu gọi dưới 30 phút/tháng, với cước SMS rẻ gần 50% so với cước tin nhắn thông thường.', 'Trả trước', 'images/f70KgH7jX3AhZUPwMAEor23ZhzorGOP4WEArKDRp.jpg', 1, '2025-01-21 01:44:55', '2025-01-21 01:44:55'),
(2, 'MobiCard', 'MobiCard là gói cước trả trước được thiết kế phù hợp với người không có nhu cầu nhắn tin nhiều và gọi khoảng từ 30 tới 135 phút/tháng. Ngoài chất lượng cuộc gọi hoàn hảo, bạn sẽ hoàn toàn kiểm soát chi phí kết nối phát sinh.', 'Trả trước', 'images/sdXkDeqP2l7UVGjxvXvhJrShY4jxIcfcFkhdhueM.jpg', 1, '2025-01-21 01:50:34', '2025-01-21 01:50:34'),
(3, 'MobiGold', 'MobiGold là gói cước trả sau có chất lượng cuộc gọi hoàn hảo với cước gọi rẻ hơn 30% so với cước gọi thông thường, được thiết kế phù hợp với người phải liên lạc nhiều và dùng hơn 135 phút/tháng.', 'Trả sau', 'images/95cFPV7QsTlk9pwSHe3Skz4lwUTLz5IX7CfEvtVn.jpg', 1, '2025-01-21 13:17:47', '2025-01-21 13:17:47'),
(6, 'MobiF', 'MobiF là gói cước trả sau với ưu đãi miễn phí cước thuê bao tháng và hỗ trợ khách hàng kiểm soát mức chi tiêu của mình. Khi đã dùng hết hạn mức, khách hàng có thể thanh toán/nạp tiền thêm để tiếp tục sử dụng như với thuê bao trả trước.', 'Trả sau', 'images/9v5CkMARXZ7DzfJlrp3O6K1tEhrH1g8vollOvaV5.jpg', 1, '2025-01-21 13:20:35', '2025-01-21 13:20:35'),
(7, 'Fast Connect', 'Fast Connect là dịch vụ giúp bạn có thể truy cập Internet băng rộng di động (Mobile Broadband) và gửi tin nhắn SMS trong phạm vi vùng phủ sóng của mạng MobiFone thông qua các thiết bị cho phép truy cập Internet trên nền công nghệ GPRS/EDGE/3G.', 'Fast Connect', 'images/sO8jBsHTTmQy4FirYCGF2FFU1B3vgfRLSxehKlqH.jpg', 1, '2025-01-21 13:25:06', '2025-01-21 13:25:06'),
(20, 'TEST', 'TEST', 'Fast Connect', 'subscription_types/PZClhqsgirUbYxCgaEg9Mu1tsKQRS1YD6QqCG6sW.jpg', 0, '2025-03-26 12:58:10', '2025-03-26 14:01:48');
INSERT INTO `tuyendung` (`id`, `vi_tri`, `mo_ta`, `yeu_cau`, `luong`, `thoi_gian_ung_tuyen`, `created_at`, `updated_at`) VALUES
(1, 'Bán hàng, Marketing', 'Thực hiện chiến lược marketing, quảng bá sản phẩm, tìm kiếm khách hàng, xây dựng mối quan hệ với đối tác.', 'Kỹ năng giao tiếp, lập kế hoạch, phân tích thị trường, sáng tạo, kinh nghiệm bán hàng và marketing.', '7.000.000 - 15.000.000 VND (Có thể thay đổi tùy vào kinh nghiệm và công ty)', '9999-12-31', '2025-01-17 07:59:02', '2025-01-18 09:05:34'),
(2, 'Công nghệ thông tin', 'Lập trình, phát triển phần mềm, bảo trì hệ thống, triển khai các dự án công nghệ thông tin.', 'Thành thạo các ngôn ngữ lập trình, khả năng phân tích và giải quyết vấn đề, kinh nghiệm làm việc với các công cụ và nền tảng IT.', '10.000.000 - 30.000.000 VND (Tùy thuộc vào kinh nghiệm và kỹ năng)', '2025-01-17', '2025-01-17 08:11:21', '2025-01-17 08:11:21'),
(3, 'Hành chính, văn phòng', 'Quản lý hồ sơ, tài liệu, xử lý công văn, chuẩn bị báo cáo, hỗ trợ các phòng ban khác.', 'Kỹ năng tổ chức công việc, quản lý thời gian, giao tiếp tốt, sử dụng thành thạo phần mềm văn phòng.', '6.000.000 - 12.000.000 VND', '2025-01-17', '2025-01-17 08:12:12', '2025-01-17 08:12:12'),
(4, 'IT phần mềm', 'Phát triển phần mềm, thiết kế hệ thống, kiểm tra và bảo trì các ứng dụng phần mềm.', 'Kiến thức vững về các ngôn ngữ lập trình, kỹ năng làm việc nhóm, khả năng giải quyết vấn đề.', '10.000.000 - 25.000.000 VND', '2025-01-18', '2025-01-17 08:13:30', '2025-01-17 08:13:30'),
(8, 'Kế toán', '- Lập tờ khai/báo cáo thuế giá trị gia tăng, thuế thu nhập cá nhân và các loại thuế khác theo quy định.\r\n\r\n- Thực hiện kiểm tra đối chiếu hóa đơn GTGT theo dữ liệu cơ quan thuế với bảng kê thuế đầu vào, đầu ra phát sinh tại đơn vị.\r\n\r\n- Kiểm tra hóa đơn đầu vào đảm bảo phát hiện các hóa đơn không hợp pháp.\r\n\r\n- Làm việc cơ quan thuế khi có phát sinh các nghiệp vụ liên quan đến thuế\r\n\r\n- Chủ trì xử lý các lỗi về hóa đơn GTGT đầu ra toàn Công ty.\r\n\r\n- Cập nhật  kịp thời các thông tin về Luật thuế, thông báo kịp thời các thay đổi có liên quan đến chính sách thuế có liên quan đến hoạt động sản xuất kinh doanh của Công ty\r\n\r\n- Lập báo cáo tình hình sử dụng hoá đơn toàn công ty.\r\n\r\n- Thực hiện hạch toán kế toán và lưu trữ chứng từ theo đúng quy định\r\n\r\n- Khả năng sử dụng thành thạo các phần mềm in học văn phòng như Excel, Word, PowerPoint.\r\n\r\n- Kỹ năng phân tích, tổng hợp số liệu\r\n\r\n- Kỹ năng giao tiếp và xử lý tình huống.\r\n\r\n- Trung thực, cẩn thận và có tinh thần trách nhiệm cao, đảm bảo thực hiện công việc được giao đúng thời hạn quy định.', 'Tốt nghiệp Đại học – Hệ chính quy chuyên ngành Kế toán (chuyên ngành Kế toán kiểm toán, kế toán ngân hàng, kế toán tài chính,...thuộc một trong các trường:\r\n\r\n+ Các trường Đại học công lập trong nước.\r\n\r\n+ Hoặc các trường Đại học nước ngoài thuộc nhóm 1200 trường Đại học tốt nhất tại bảng xếp hạng toàn cầu (World University/ World Universities/ Global Universities) của các website: timeshighereducation.com, topuniversities.com, shanghairanking.com, usnews.com hoặc thuộc nhóm 100 trường đại học tốt nhất tại bảng xếp hạng National Liberal Arts Colleges của website usnews.com (Thời gian bảng xếp hạng phải thuộc một trong các năm từ thời điểm ứng viên theo học đến thời điểm ứng viên ứng tuyển)', 'Tổng thu nhập trước thuế lên đến 250 triệu năm đầu tiên; xét tăng lương hàng năm, thu nhập lên đến 300 triệu/năm.', '9999-12-31', '2025-01-17 10:14:14', '2025-01-17 10:14:14');
