DELIMITER $$
--
-- Thủ tục
--
CREATE DEFINER=`root`@`localhost` PROCEDURE `GeneratePhoneNumbers` ()   BEGIN
    DECLARE i INT DEFAULT 1;
    DECLARE phone_prefix VARCHAR(3);
    
    -- Danh sách các đầu số
    DECLARE prefixes VARCHAR(12) DEFAULT '093,090,076,078';

    -- Duyệt từng đầu số
    WHILE i <= 4 DO
        SET phone_prefix = SUBSTRING_INDEX(SUBSTRING_INDEX(prefixes, ',', i), ',', -1);

        -- Tạo 20 số thuê bao cho mỗi đầu số
        SELECT 
            CONCAT(phone_prefix, LPAD(FLOOR(RAND() * 10000000), 7, '0')) AS so_thue_bao,
            ELT(FLOOR(1 + (RAND() * 2)), 'tra_truoc', 'tra_sau') AS loai_thue_bao,
            ELT(FLOOR(1 + (RAND() * 5)), 'Hà Nội', 'Hồ Chí Minh', 'Đà Nẵng', 'Cần Thơ', 'Toàn quốc') AS khu_vuc,
            FLOOR(RAND() * 100000) AS phi_hoa_mang,
            ELT(FLOOR(1 + (RAND() * 3)), 'chua_su_dung', 'giu_so', 'hoa_mang') AS trang_thai,
            ELT(FLOOR(1 + (RAND() * 2)), 'so_thuong', 'so_vip') AS loai_so,
            FLOOR(RAND() * 300000) AS phi_giu_so,
            NOW(), NOW()
        FROM (SELECT 1 UNION SELECT 2 UNION SELECT 3 UNION SELECT 4 UNION SELECT 5
              UNION SELECT 6 UNION SELECT 7 UNION SELECT 8 UNION SELECT 9 UNION SELECT 10
              UNION SELECT 11 UNION SELECT 12 UNION SELECT 13 UNION SELECT 14 UNION SELECT 15
              UNION SELECT 16 UNION SELECT 17 UNION SELECT 18 UNION SELECT 19 UNION SELECT 20) AS numbers;

        SET i = i + 1;
    END WHILE;
END$$

DELIMITER ;

